import math
import random

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def is_prime(n):
    if n < 2:
        return False
    if n == 2 or n == 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def pollard_rho(n):
    if n % 2 == 0:
        return 2

    x = random.randint(2, n - 1)
    y = x
    c = random.randint(1, n - 1)
    d = 1

    def f(val):
        return (val * val + c) % n

    while d == 1:
        x = f(x)
        y = f(f(y))
        d = gcd(abs(x - y), n)

        if d == n:
            x = random.randint(2, n - 1)
            y = x
            c = random.randint(1, n - 1)
            d = 1
            def f(val):
                return (val * val + c) % n
    return d

def prime_factorization(n):
    factors = []
    if n < 2:
        return factors

    stack = [n]

    while stack:
        current_n = stack.pop()

        if current_n == 1:
            continue

        if is_prime(current_n):
            factors.append(current_n)
        else:
            factor = pollard_rho(current_n)
            stack.append(factor)
            stack.append(current_n // factor)

    factors.sort()
    return factors
